const body = $input.first().json.body || $input.first().json;
const email = (body.email || '').toLowerCase().trim();
const name = body.name || '';
const source = body.source || 'unknown';
const productType = body.product_type || 'unknown';
const language = (body.language || 'EN').toUpperCase();

if (!email) {
  throw new Error('email is required');
}

// Map source/product_type -> Brevo list. Replace the placeholder IDs
// below with the real numeric list IDs from your Brevo account
// (Brevo > Contacts > Lists). See docs/BREVO_LISTS_TAGS.md.
const LIST_IDS = {
  'digital-products': Number($env.BREVO_LIST_DIGITAL_PRODUCTS || 0),
  'ecom-merch': Number($env.BREVO_LIST_ECOM_MERCH || 0),
  'general-leads': Number($env.BREVO_LIST_GENERAL_LEADS || 0),
  'vip': Number($env.BREVO_LIST_VIP || 0)
};

function resolveListKey(source, productType) {
  const s = (source || '').toLowerCase();
  const p = (productType || '').toLowerCase();
  if (p.includes('gumroad') || p.includes('digital') || s.includes('gumroad') || s.includes('waitlist')) {
    return 'digital-products';
  }
  if (p.includes('merch') || p.includes('shop') || s.includes('shop') || s.includes('ecom')) {
    return 'ecom-merch';
  }
  return 'general-leads';
}

const listKey = resolveListKey(source, productType);
const listId = LIST_IDS[listKey];

// Welcome-sequence template per list + language, see docs/WELCOME_SEQUENCES.md
const TEMPLATE_IDS = {
  'digital-products': { DE: Number($env.BREVO_TPL_DIGITAL_DE || 0), EN: Number($env.BREVO_TPL_DIGITAL_EN || 0) },
  'ecom-merch': { DE: Number($env.BREVO_TPL_ECOM_DE || 0), EN: Number($env.BREVO_TPL_ECOM_EN || 0) },
  'general-leads': { DE: Number($env.BREVO_TPL_GENERAL_DE || 0), EN: Number($env.BREVO_TPL_GENERAL_EN || 0) }
};
const lang = (language === 'DE') ? 'DE' : 'EN';
const templateId = (TEMPLATE_IDS[listKey] || {})[lang] || 0;

return [{
  json: {
    email,
    name,
    source,
    productType,
    language: lang,
    listKey,
    listId,
    templateId
  }
}];

