const fs = require('fs');
const data = $('Map Source -> List/Tags').item.json;
const entry = {
  timestamp: new Date().toISOString(),
  workflow: 'optin-to-brevo',
  email: data.email,
  source: data.source,
  productType: data.productType,
  language: data.language,
  list: data.listKey,
  listId: data.listId
};
try {
  fs.appendFileSync('/root/n8n_log.json', JSON.stringify(entry) + '\n');
} catch (e) {
  // logging must never fail the contact creation
}
return [{ json: entry }];

